\begin{lemma}[Restriction of a presentation to a basic open]
  \label{def:presentation_basic_open}
  \lean{AlgebraicGeometry.Scheme.Modules.MatrixPresentationBasicOpen}
  \leanok
  \uses{def:matrix_presentation_base_change, def:presentation_chart}
  Let \(P = (\psi, \pi)\) be a matrix presentation of
  \(\Gamma(\mathcal G, V)\) by \(e\) generators over an affine open \(V\), and
  \(f \in \Gamma(X, V)\).  Since \(\mathcal G\) is quasi-coherent, restriction
  identifies \(\Gamma(\mathcal G, D(f))\) with the localization
  \(\Gamma(\mathcal G, V)_f\); base-changing \(P\) along
  \(\Gamma(X, V) \to \Gamma(X, D(f))\) therefore yields a matrix presentation
  of \(\Gamma(\mathcal G, D(f))\) by \(e\) generators, whose relation matrix
  is the entrywise restriction \(\psi|_{D(f)}\).
\end{lemma}

\begin{proof}
  \leanok
  Quasi-coherence gives that the restriction map exhibits
  \(\Gamma(\mathcal G, D(f))\) as \(\Gamma(\mathcal G, V) \otimes_{\Gamma(X, V)}
  \Gamma(X, D(f))\).  Base change of the presentation \(P\) along this map
  (\cref{def:matrix_presentation_base_change}) presents this tensor product;
  transporting along the localization isomorphism produces a presentation of
  \(\Gamma(\mathcal G, D(f))\) with the same, entrywise restricted, relation
  matrix.
\end{proof}
